mapper.select:
SELECT l1.ID, l1.LABELNAME, l1.LABELCODE, l1.LABELLEVEL, l1.CLASSID, l1.LABELDESCRIBE, l1.AUTHOR, l1.labelLevelStr, CASE WHEN r1.tableCount IS NULL THEN 0 ELSE r1.tableCount END AS tableCount, r2.CODETEXT AS classIdStr, l1.moddate, DATE_FORMAT(l1.moddate, '%Y-%m-%d %H:%i:%s') AS moddateStr FROM ( SELECT ID, LABELNAME, LABELCODE, LABELLEVEL, CLASSID, LABELDESCRIBE, AUTHOR, label_name AS labelLevelStr, moddate FROM ( SELECT l.*, r.label_name, ROW_NUMBER() OVER (PARTITION BY LABELCODE ORDER BY moddate DESC) AS num FROM synlte.LABELS l LEFT JOIN DSM_LABEL_CODE_TABLE r ON l.LABELLEVEL = r.label_level ) t WHERE t.num = 1 ) l1 LEFT JOIN ( SELECT LABELLEVEL, labelcode, tableCount FROM ( SELECT 1 AS LABELLEVEL, SJZYBQ1 AS labelcode, COUNT(DISTINCT SJXJBM) AS tableCount FROM synlte.PUBLIC_DATA_INFO WHERE SJZYBQ1 IS NOT NULL AND zyzt = '1' GROUP BY SJZYBQ1 UNION ALL SELECT 2 AS LABELLEVEL, SJZYBQ2 AS labelcode, COUNT(DISTINCT SJXJBM) AS tableCount FROM synlte.PUBLIC_DATA_INFO WHERE SJZYBQ2 IS NOT NULL AND zyzt = '1' GROUP BY SJZYBQ2 UNION ALL SELECT 3 AS LABELLEVEL, SJZYBQ3 AS labelcode, COUNT(DISTINCT SJXJBM) AS tableCount FROM synlte.PUBLIC_DATA_INFO WHERE SJZYBQ3 IS NOT NULL AND zyzt = '1' GROUP BY SJZYBQ3 UNION ALL SELECT 4 AS LABELLEVEL, SJZYBQ4 AS labelcode, COUNT(DISTINCT SJXJBM) AS tableCount FROM synlte.PUBLIC_DATA_INFO WHERE SJZYBQ4 IS NOT NULL AND zyzt = '1' GROUP BY SJZYBQ4 UNION ALL SELECT 5 AS LABELLEVEL, SJZYBQ5 AS labelcode, COUNT(DISTINCT SJXJBM) AS tableCount FROM synlte.PUBLIC_DATA_INFO WHERE SJZYBQ5 IS NOT NULL AND zyzt = '1' GROUP BY SJZYBQ5 UNION ALL SELECT 6 AS LABELLEVEL, SJZYBQ6 AS labelcode, COUNT(DISTINCT SJXJBM) AS tableCount FROM synlte.PUBLIC_DATA_INFO WHERE SJZYBQ6 IS NOT NULL AND zyzt = '1' GROUP BY SJZYBQ6 ) t ) r1 ON l1.LABELLEVEL = r1.LABELLEVEL AND UPPER(l1.LABELCODE) = UPPER(r1.labelcode) LEFT JOIN (SELECT DISTINCT codename, CODETEXT FROM V_CLASSIFY_INFO WHERE PARCODEID = #{sjzzflCodeId}) r2 ON l1.CLASSID = r2.codename
ORDER BY ${sort} ${sortOrder}
ORDER BY moddate DESC

select labelname as label, labelcode as value from (select labelname, labelcode, classid, labellevel, row_number() over(partition by upper(labelcode) order by moddate desc) rn from synlte.LABELS
labellevel = #{labelLevel}
and upper(classid) = upper(#{classId})
) tt where rn = 1

select labelname, labelcode, labellevel, classid from (select labelname, labelcode, labellevel, classid, row_number() over(partition by upper(labelcode) order by moddate desc) rn from synlte.LABELS where labelcode in (
#{item,jdbcType=VARCHAR}
)) tt where rn = 1 order by labellevel asc
